import { Component, OnInit, OnDestroy } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { Subject, timer } from 'rxjs';
import { takeUntil, switchMap } from 'rxjs/operators';
import { ContestationService } from '../../services/contestation.service';
import { ContestationResponse, ContestationStatus } from '../../models/contestation.model';

@Component({
  selector: 'app-contestation-detail',
  templateUrl: './contestation-detail.component.html'
})
export class ContestationDetailComponent implements OnInit, OnDestroy {
  private destroy$ = new Subject<void>();

  contestation: ContestationResponse | null = null;
  loading = false;
  errorMsg = '';
  successMsg = '';
  autoRefresh = false;
  cancelLoading = false;
  replayLoading = false;

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    private contestationService: ContestationService
  ) {}

  ngOnInit(): void {
    const requestId = this.route.snapshot.paramMap.get('id');
    if (requestId) {
      this.loadContestation(requestId);
    }
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  loadContestation(requestId: string): void {
    this.loading = true;
    this.errorMsg = '';

    this.contestationService.getById(requestId).subscribe({
      next: (data) => {
        this.contestation = data;
        this.loading = false;
      },
      error: (err) => {
        this.errorMsg = err.error?.message || 'Contestação não encontrada';
        this.loading = false;
      }
    });
  }

  refresh(): void {
    if (this.contestation) {
      this.loadContestation(this.contestation.requestId);
    }
  }

  toggleAutoRefresh(): void {
    this.autoRefresh = !this.autoRefresh;
    if (this.autoRefresh && this.contestation) {
      const id = this.contestation.requestId;
      timer(5000, 5000)
        .pipe(
          takeUntil(this.destroy$),
          switchMap(() => this.contestationService.getById(id))
        )
        .subscribe({
          next: (data) => { this.contestation = data; },
          error: () => {}
        });
    } else {
      this.destroy$.next();
    }
  }

  cancelContestation(): void {
    if (!this.contestation) return;
    this.cancelLoading = true;
    this.successMsg = '';
    this.errorMsg = '';

    this.contestationService.cancelContestation(this.contestation.requestId).subscribe({
      next: (data) => {
        this.contestation = data;
        this.successMsg = 'Contestação cancelada com sucesso!';
        this.cancelLoading = false;
      },
      error: (err) => {
        this.errorMsg = err.error?.message || 'Erro ao cancelar contestação';
        this.cancelLoading = false;
      }
    });
  }

  replayContestation(): void {
    if (!this.contestation) return;
    this.replayLoading = true;
    this.successMsg = '';
    this.errorMsg = '';

    this.contestationService.replayContestation(this.contestation.requestId).subscribe({
      next: () => {
        this.successMsg = 'Replay iniciado! Acompanhe as mudanças de status.';
        this.replayLoading = false;
        setTimeout(() => this.refresh(), 2000);
      },
      error: (err) => {
        this.errorMsg = err.error?.message || 'Erro ao iniciar replay';
        this.replayLoading = false;
      }
    });
  }

  getStatusClass(status: ContestationStatus): string {
    const map: Record<ContestationStatus, string> = {
      'EM_ANDAMENTO': 'badge-em-andamento',
      'SUCESSO': 'badge-sucesso',
      'CANCELADO': 'badge-cancelado',
      'CALLBACK_FALHA': 'badge-callback-falha'
    };
    return map[status] || '';
  }

  getStatusIcon(status: ContestationStatus): string {
    const icons: Record<ContestationStatus, string> = {
      'EM_ANDAMENTO': '⏳',
      'SUCESSO': '✅',
      'CANCELADO': '🚫',
      'CALLBACK_FALHA': '❌'
    };
    return icons[status] || '•';
  }

  canCancel(): boolean {
    return this.contestation?.communicationStatus === 'EM_ANDAMENTO';
  }

  canReplay(): boolean {
    const status = this.contestation?.communicationStatus;
    return status === 'CALLBACK_FALHA';
  }

  goBack(): void {
    this.router.navigate(['/contestations']);
  }

  parsedPayload(): string {
    try {
      return JSON.stringify(JSON.parse(this.contestation?.payload || '{}'), null, 2);
    } catch {
      return this.contestation?.payload || '';
    }
  }
}
<div class="page-content">
  <!-- Header -->
  <div class="d-flex justify-between align-center mb-2">
    <div class="page-title" style="margin-bottom:0">
      <button class="btn btn-secondary btn-sm" (click)="goBack()">← Voltar</button>
      <span>🔍 Detalhe da Contestação</span>
    </div>
    <div class="d-flex gap-2">
      <button
        class="btn btn-sm"
        [class.btn-primary]="autoRefresh"
        [class.btn-secondary]="!autoRefresh"
        (click)="toggleAutoRefresh()">
        {{ autoRefresh ? '🔴 Stop Auto Refresh' : '🔄 Auto Refresh' }}
      </button>
      <button class="btn btn-secondary btn-sm" (click)="refresh()">🔃 Atualizar</button>
    </div>
  </div>

  <!-- Loading -->
  <div *ngIf="loading" class="text-center" style="padding:60px">
    <div class="spinner spinner-dark" style="width:36px;height:36px;margin:0 auto"></div>
    <p class="text-muted mt-1">Carregando...</p>
  </div>

  <!-- Erro -->
  <div *ngIf="errorMsg && !loading" class="alert alert-danger">⚠️ {{ errorMsg }}</div>
  <div *ngIf="successMsg" class="alert alert-success">✅ {{ successMsg }}</div>

  <!-- Conteúdo -->
  <ng-container *ngIf="contestation && !loading">
    <!-- Status Card -->
    <div class="card">
      <div class="card-header">
        <h2>
          {{ getStatusIcon(contestation.communicationStatus) }}
          Status Atual
        </h2>
        <div class="d-flex gap-2 align-center">
          <span class="badge" [ngClass]="getStatusClass(contestation.communicationStatus)">
            {{ contestation.communicationStatus }}
          </span>
          <span class="text-muted">{{ contestation.communicationType }}</span>
        </div>
      </div>

      <div class="detail-grid">
        <div class="detail-item">
          <span class="label">Request ID</span>
          <span class="value text-mono">{{ contestation.requestId }}</span>
        </div>
        <div class="detail-item">
          <span class="label">Contestation ID</span>
          <span class="value text-mono">{{ contestation.contestationId }}</span>
        </div>
        <div class="detail-item">
          <span class="label">Correlation ID</span>
          <span class="value text-mono">{{ contestation.correlationId }}</span>
        </div>
        <div class="detail-item">
          <span class="label">Recebido em</span>
          <span class="value">{{ contestation.receivedAt | date:'dd/MM/yyyy HH:mm:ss' }}</span>
        </div>
        <div class="detail-item">
          <span class="label">Atualizado em</span>
          <span class="value">{{ contestation.updatedAt | date:'dd/MM/yyyy HH:mm:ss' }}</span>
        </div>
      </div>

      <!-- Último erro -->
      <div *ngIf="contestation.lastError" class="alert alert-danger mt-2">
        <strong>⚠️ Último Erro:</strong><br />
        <span class="text-mono" style="font-size:12px">{{ contestation.lastError }}</span>
      </div>
    </div>

    <!-- Payload -->
    <div class="card" *ngIf="contestation.payload">
      <div class="card-header">
        <h2>📦 Payload</h2>
      </div>
      <pre style="background:#f5f7fa;padding:16px;border-radius:6px;font-size:12px;overflow:auto;max-height:200px">{{ parsedPayload() }}</pre>
    </div>

    <!-- Ações -->
    <div class="card">
      <div class="card-header">
        <h2>⚡ Ações</h2>
      </div>
      <div class="d-flex gap-2">
        <button
          class="btn btn-danger"
          (click)="cancelContestation()"
          [disabled]="!canCancel() || cancelLoading"
          title="{{ canCancel() ? 'Cancelar esta contestação' : 'Apenas EM_ANDAMENTO pode ser cancelado' }}">
          <span *ngIf="cancelLoading" class="spinner"></span>
          🚫 {{ cancelLoading ? 'Cancelando...' : 'Cancelar' }}
        </button>

        <button
          class="btn btn-secondary"
          (click)="replayContestation()"
          [disabled]="!canReplay() || replayLoading"
          title="{{ canReplay() ? 'Reenfileirar para reprocessamento' : 'Replay disponível apenas para CALLBACK_FALHA' }}">
          <span *ngIf="replayLoading" class="spinner spinner-dark"></span>
          🔁 {{ replayLoading ? 'Reprocessando...' : 'Replay (Admin)' }}
        </button>
      </div>
      <p class="text-muted mt-1" style="font-size:11px">
        Cancelar: disponível apenas para status EM_ANDAMENTO |
        Replay: disponível para CALLBACK_FALHA
      </p>
    </div>

    <!-- Histórico de Auditoria -->
    <div class="card">
      <div class="card-header">
        <h2>📜 Histórico de Auditoria</h2>
        <span class="text-muted">{{ contestation.auditHistory?.length || 0 }} evento(s)</span>
      </div>

      <div *ngIf="contestation.auditHistory?.length; else noAudit" class="audit-timeline">
        <div *ngFor="let log of contestation.auditHistory" class="audit-item">
          <div class="audit-time">{{ log.createdAt | date:'dd/MM/yyyy HH:mm:ss' }}</div>
          <div class="audit-status">
            <span *ngIf="log.fromStatus" class="badge badge-cancelado" style="font-size:10px">
              {{ log.fromStatus }}
            </span>
            <span *ngIf="log.fromStatus">→</span>
            <span class="badge" [ngClass]="getStatusClass(log.toStatus)" style="font-size:10px">
              {{ log.toStatus }}
            </span>
          </div>
          <div class="audit-msg">{{ log.message }}</div>
        </div>
      </div>

      <ng-template #noAudit>
        <div class="empty-state" style="padding:24px">
          <p class="text-muted">Nenhum log de auditoria disponível.</p>
        </div>
      </ng-template>
    </div>
  </ng-container>
</div>
